// Provide a researched content item for manual testing.
return [{
  json: {
    id: 'manual:https://example.com/ai-agent',
    source: 'manual',
    title: 'AI Agent 與工作流',
    url: 'https://example.com/ai-agent',
    language: 'zh-TW',
    content: 'AI Agent 不應只負責生成文字，也應根據工具結果規劃下一步。',
    score: 85,
    shouldWrite: true,
    analysis: {
      topic: 'AI Agent',
      coreIdea: 'AI Agent 應根據工具結果規劃下一步',
      audience: 'n8n 與自動化使用者',
      angles: ['Agent orchestration'],
      keywords: ['AI Agent', 'workflow automation'],
      researchQuestions: ['什麼是 AI Agent？'],
      riskNotes: []
    },
    research: {
      query: 'AI Agent workflow automation',
      sources: [],
      sourceCount: 0,
      notes: ''
    },
    metadata: {
      createdAt: new Date().toISOString(),
      status: 'researched'
    }
  }
}];

// Build a semantic query representing the article topic and intended angle.
const input = $input.first().json;
const body = input.body ?? input;

if (!body.analysis?.topic || !body.analysis?.coreIdea) {
  throw new Error('analysis.topic and analysis.coreIdea are required');
}

if (String(body.qdrantBaseUrl).includes('YOUR-QDRANT-CLUSTER')) {
  throw new Error('SetRagConfig.qdrantBaseUrl must be replaced with your Qdrant Cloud URL');
}

const queryText = [
  body.analysis.topic,
  body.analysis.coreIdea,
  ...(Array.isArray(body.analysis.angles) ? body.analysis.angles.slice(0, 3) : []),
  ...(Array.isArray(body.analysis.keywords) ? body.analysis.keywords.slice(0, 5) : [])
].filter(Boolean).join('\n');

return [{
  json: {
    original: body,
    queryText,
    qdrantBaseUrl: String(body.qdrantBaseUrl).replace(/\/$/, ''),
    collection: body.collection,
    topK: Number(body.topK),
    scoreThreshold: Number(body.scoreThreshold),
    embeddingModel: body.embeddingModel
  }
}];

// Validate and extract the NVIDIA embedding vector.
const response = $input.first().json;
const request = $('BuildStyleQuery').first().json;
const vector = response.data?.[0]?.embedding;

if (!Array.isArray(vector) || vector.length === 0) {
  throw new Error('NVIDIA embedding response does not contain data[0].embedding');
}

return [{
  json: {
    ...request,
    vector
  }
}];

