// Merge retrieved style examples into the researched content contract.
const response = $input.first().json;
const request = $('ParseQueryEmbedding').first().json;
const original = request.original;
const points = response.result?.points ?? response.result ?? [];

const matches = (Array.isArray(points) ? points : [])
  .map((point) => ({
    id: String(point.id ?? ''),
    score: Number(point.score ?? 0),
    title: String(point.payload?.title ?? ''),
    url: String(point.payload?.url ?? ''),
    text: String(point.payload?.text ?? point.payload?.content ?? ''),
    section: String(point.payload?.section ?? ''),
    styleTags: Array.isArray(point.payload?.style_tags) ? point.payload.style_tags : []
  }))
  .filter((match) => match.text)
  .slice(0, request.topK);

return [{
  json: {
    ...original,
    styleRag: {
      query: request.queryText,
      model: request.embeddingModel,
      collection: request.collection,
      matches,
      matchCount: matches.length
    },
    metadata: {
      ...original.metadata,
      styleRetriever: '05-style-rag',
      styleRetrieverVersion: '0.5.2',
      status: 'style_retrieved',
      styleRetrievedAt: new Date().toISOString()
    }
  }
}];

// Determine whether the Qdrant collection exists.
const response = $input.first().json;
const request = $('BuildStyleQuery').first().json;
const statusCode = response.statusCode ?? 0;

return [{
  json: {
    ...request,
    collectionExists: statusCode >= 200 && statusCode < 300,
    collectionStatusCode: statusCode
  }
}];

// Restore the style query context after collection creation.
const request = $('BuildStyleQuery').first().json;
return [{ json: request }];
